customCSS:
/* Summer Vibes - Tropical Sunset Background */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&family=Inter:wght@300;400;500;600&family=Fira+Code&display=swap');

/* Static sunset gradient background */
.cyber-glow {
  background: 
    radial-gradient(ellipse at 50% 120%, rgba(255, 140, 66, 0.25) 0%, transparent 50%),
    radial-gradient(ellipse at 70% 100%, rgba(244, 114, 182, 0.15) 0%, transparent 40%),
    linear-gradient(180deg, rgba(124, 58, 237, 0.05) 0%, rgba(244, 114, 182, 0.08) 50%, rgba(255, 140, 66, 0.12) 100%);
  animation: none;
}

.cyber-particles { display: none; }

.stat-card {
  border-radius: 14px;
  border: 1px solid rgba(255, 140, 66, 0.2);
}

.stat-card::before {
  background: linear-gradient(135deg, #ffd93d, #ff8c42, #f472b6);
}

.stat-card:hover {
  box-shadow: 0 0 25px rgba(255, 140, 66, 0.2);
}

.celebration-title {
  background: linear-gradient(135deg, #ffd93d, #ff8c42, #f472b6);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card { border-radius: 14px; }
